40	    // Safe one-time migrations: ADD COLUMN IF NOT EXISTS never fails on re-deploy
41	    const schema = process.env.SCHEMA ? `"${process.env.SCHEMA}".` : '';
42	    sequelize.query(`ALTER TABLE ${schema}"RFQItem" ADD COLUMN IF NOT EXISTS "rfqItem_duty_rate_equation" VARCHAR(500)`)
43	      .catch(err => console.warn('Migration rfqItem_duty_rate_equation skipped:', err.message));
44	    sequelize.query(`ALTER TABLE ${schema}"customers" ADD COLUMN IF NOT EXISTS customers_logo VARCHAR(500)`)
45	      .catch(err => console.warn('Migration customers_logo skipped:', err.message));
46	    sequelize.query(`CREATE TABLE IF NOT EXISTS ${schema}app_settings (key VARCHAR(100) PRIMARY KEY, value TEXT, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW())`)
47	      .catch(err => console.warn('Migration app_settings skipped:', err.message));
48	    sequelize.query(`ALTER TABLE ${schema}"users" ADD COLUMN IF NOT EXISTS profile_photo TEXT`)
49	      .catch(err => console.warn('Migration users.profile_photo skipped:', err.message));
50	    // RFQItem.price_sales_snapshots — per-row JSON map of price_sales colId ->
51	    // {duty_rate, duty_dollar, container_price, at}, snapshotting the cost inputs at
52	    // the moment each "Price for Sales" cell was last populated (shown as a cell tooltip).
53	    sequelize.query(`ALTER TABLE ${schema}"RFQItem" ADD COLUMN IF NOT EXISTS "rfqItem_price_sales_snapshots" TEXT`)
54	      .catch(err => console.warn('Migration rfqItem_price_sales_snapshots skipped:', err.message));
55	    // RFQItem.factories_step_at — timestamp for when an item moves to @factories.
56	    // The mixed-case identifier must be quoted to match Sequelize's generated SQL.
57	    sequelize.query(`ALTER TABLE ${schema}"RFQItem" ADD COLUMN IF NOT EXISTS "rfqItem_factories_step_at" TIMESTAMPTZ`)
58	      .catch(err => console.warn('Migration rfqItem_factories_step_at skipped:', err.message));
59	    // Clean up the empty lowercase orphan column an earlier UNQUOTED version of the
60	    // migration above accidentally created (Postgres folds unquoted identifiers to
61	    // lowercase). It is distinct from the correct mixed-case column and unused.
62	    // Quoted-lowercase DROP targets only the orphan; safe + idempotent via IF EXISTS.
63	    sequelize.query(`ALTER TABLE ${schema}"RFQItem" DROP COLUMN IF EXISTS "rfqitem_price_sales_snapshots"`)
64	      .catch(err => console.warn('Migration drop orphan rfqitem_price_sales_snapshots skipped:', err.message));
65	    // RFQVendor.requote_requested — true when Sourcing has asked the factory to
66	    // refresh a stale quote. Drives the orange highlight + "Quoted <date>" tooltip
67	    // in the RFQ detail grid; cleared when the vendor re-quotes or clicks "Keep Price".
68	    sequelize.query(`ALTER TABLE ${schema}"RFQVendor" ADD COLUMN IF NOT EXISTS "requote_requested" BOOLEAN DEFAULT false`)
69	      .catch(err => console.warn('Migration RFQVendor.requote_requested skipped:', err.message));
70	    // Factory.factory_country — country where the factory operates (FOB origin).
71	    // Used to auto-fill FOB Country on quote rows and to match the Trump 2025
72	    // reciprocal tariff rate when calculating duty.
73	    sequelize.query(`ALTER TABLE ${schema}"Factory" ADD COLUMN IF NOT EXISTS factory_country VARCHAR(255)`)
74	      .catch(err => console.warn('Migration Factory.factory_country skipped:', err.message));
75	    // One-time backfill: set factory_country from the most common vendor_country
76	    // among vendors linked to each factory. Only fills NULLs so it is safe to re-run.
77	    sequelize.query(`
78	      UPDATE ${schema}"Factory" f
79	      SET factory_country = sub.country
80	      FROM (
81	        SELECT factory_id_fk, vendor_country AS country,
82	               ROW_NUMBER() OVER (PARTITION BY factory_id_fk ORDER BY COUNT(*) DESC) AS rn
83	        FROM ${schema}vendor
84	        WHERE factory_id_fk IS NOT NULL AND vendor_country IS NOT NULL AND vendor_country <> ''
85	        GROUP BY factory_id_fk, vendor_country
86	      ) sub
87	      WHERE sub.rn = 1 AND sub.factory_id_fk = f.id
88	        AND (f.factory_country IS NULL OR f.factory_country = '')
89	    `).catch(err => console.warn('Backfill Factory.factory_country skipped:', err.message));
90	}
